/**
 * Socket.io Handler
 * Real-time events: chat, notifications, pickup tracking, donation alerts
 */

const jwt = require('jsonwebtoken');
const User = require('../models/User');
const logger = require('../config/logger');

/**
 * Initialize Socket.io on the HTTP server
 * @param {import('socket.io').Server} io
 */
const initializeSocket = (io) => {
  // ─── Online users map: userId → socketId ─────────────────────────────────
  const onlineUsers = {};

  // ─── JWT Authentication Middleware for Socket.io ──────────────────────────
  io.use(async (socket, next) => {
    try {
      const token =
        socket.handshake.auth?.token ||
        socket.handshake.headers?.authorization?.split(' ')[1];

      if (!token) {
        return next(new Error('Authentication required'));
      }

      const decoded = jwt.verify(token, process.env.JWT_SECRET);
      const user = await User.findById(decoded.id).select('name role isActive');

      if (!user || !user.isActive) {
        return next(new Error('User not found or inactive'));
      }

      socket.user = user;
      next();
    } catch (err) {
      next(new Error('Invalid token'));
    }
  });

  // ─── Connection handler ───────────────────────────────────────────────────
  io.on('connection', (socket) => {
    const userId = socket.user._id.toString();
    logger.info(`Socket connected: ${socket.user.name} (${userId})`);

    // Track online status
    onlineUsers[userId] = socket.id;
    socket.join(`user_${userId}`); // Personal room for targeted notifications

    // Broadcast online status to contacts
    socket.broadcast.emit('user:online', { userId });

    // ─── Chat Events ──────────────────────────────────────────────────────

    // Typing indicator
    socket.on('chat:typing', ({ receiverId }) => {
      socket.to(`user_${receiverId}`).emit('chat:typing', {
        senderId: userId,
        senderName: socket.user.name,
      });
    });

    socket.on('chat:stop-typing', ({ receiverId }) => {
      socket.to(`user_${receiverId}`).emit('chat:stop-typing', { senderId: userId });
    });

    // ─── Pickup Tracking Events ───────────────────────────────────────────

    // Volunteer updates their location during pickup
    socket.on('pickup:location-update', ({ pickupId, coordinates }) => {
      if (socket.user.role !== 'volunteer') return;

      // Broadcast to all parties tracking this pickup
      io.to(`pickup_${pickupId}`).emit('pickup:location', {
        pickupId,
        volunteerId: userId,
        coordinates,
        updatedAt: new Date(),
      });
    });

    // Join a pickup tracking room (donor/ngo watching a pickup)
    socket.on('pickup:track', ({ pickupId }) => {
      socket.join(`pickup_${pickupId}`);
      logger.debug(`${userId} joined pickup tracking room: pickup_${pickupId}`);
    });

    socket.on('pickup:untrack', ({ pickupId }) => {
      socket.leave(`pickup_${pickupId}`);
    });

    // ─── Notification Events ──────────────────────────────────────────────

    // Client acknowledges receiving a notification
    socket.on('notification:ack', ({ notificationId }) => {
      logger.debug(`Notification ${notificationId} acknowledged by ${userId}`);
    });

    // ─── Donation Feed Events ─────────────────────────────────────────────

    // NGO subscribes to nearby donation alerts
    socket.on('donations:subscribe', ({ lat, lng, radius }) => {
      // Store subscription info on socket
      socket.donationSubscription = { lat, lng, radius };
      socket.join('donation-feed');
      logger.debug(`${userId} subscribed to donation feed at [${lat}, ${lng}]`);
    });

    socket.on('donations:unsubscribe', () => {
      socket.leave('donation-feed');
      delete socket.donationSubscription;
    });

    // ─── Disconnect ───────────────────────────────────────────────────────
    socket.on('disconnect', (reason) => {
      delete onlineUsers[userId];
      socket.broadcast.emit('user:offline', { userId });
      logger.info(`Socket disconnected: ${socket.user.name} - ${reason}`);
    });

    // ─── Error handler ────────────────────────────────────────────────────
    socket.on('error', (err) => {
      logger.error(`Socket error for ${userId}: ${err.message}`);
    });
  });

  return onlineUsers;
};

module.exports = initializeSocket;

/**
 * Admin Controller
 * Platform administration, analytics, user management
 */

const User = require('../models/User');
const Donation = require('../models/Donation');
const Request = require('../models/Request');
const Pickup = require('../models/Pickup');
const Feedback = require('../models/Feedback');
const { asyncHandler, AppError } = require('../middleware/error');

// ─── @route  GET /api/admin/users ────────────────────────────────────────────
const getAllUsers = asyncHandler(async (req, res) => {
  const page = Math.max(parseInt(req.query.page, 10) || 1, 1);
  const limit = Math.min(parseInt(req.query.limit, 10) || 20, 100);
  const skip = (page - 1) * limit;
  const { role, isActive, search } = req.query;

  const query = {};
  if (role) query.role = role;
  if (isActive !== undefined) query.isActive = isActive === 'true';
  if (search) {
    query.$or = [
      { name: { $regex: search, $options: 'i' } },
      { email: { $regex: search, $options: 'i' } },
    ];
  }

  const [users, total] = await Promise.all([
    User.find(query).sort({ createdAt: -1 }).skip(skip).limit(limit),
    User.countDocuments(query),
  ]);

  res.status(200).json({
    success: true,
    data: {
      users,
      pagination: { total, page, limit, pages: Math.ceil(total / limit) },
    },
  });
});

// ─── @route  GET /api/admin/users/:id ────────────────────────────────────────
const getUserById = asyncHandler(async (req, res) => {
  const user = await User.findById(req.params.id);
  if (!user) throw new AppError('User not found.', 404);

  res.status(200).json({ success: true, data: { user } });
});

// ─── @route  PUT /api/admin/users/:id ────────────────────────────────────────
const updateUser = asyncHandler(async (req, res) => {
  const { isActive, role, ngoDetails } = req.body;

  const allowedUpdates = {};
  if (isActive !== undefined) allowedUpdates.isActive = isActive;
  if (role) allowedUpdates.role = role;
  if (ngoDetails) allowedUpdates.ngoDetails = ngoDetails;

  const user = await User.findByIdAndUpdate(req.params.id, allowedUpdates, {
    new: true,
    runValidators: true,
  });

  if (!user) throw new AppError('User not found.', 404);

  res.status(200).json({
    success: true,
    message: 'User updated by admin.',
    data: { user },
  });
});

// ─── @route  DELETE /api/admin/users/:id ─────────────────────────────────────
const deactivateUser = asyncHandler(async (req, res) => {
  const user = await User.findByIdAndUpdate(
    req.params.id,
    { isActive: false },
    { new: true }
  );
  if (!user) throw new AppError('User not found.', 404);

  res.status(200).json({ success: true, message: 'User deactivated.', data: { user } });
});

// ─── @route  GET /api/admin/analytics ────────────────────────────────────────
const getAnalytics = asyncHandler(async (req, res) => {
  const { period = '30' } = req.query; // days
  const daysAgo = new Date();
  daysAgo.setDate(daysAgo.getDate() - parseInt(period, 10));

  const [
    totalUsers,
    usersByRole,
    totalDonations,
    donationsByStatus,
    donationsByFoodType,
    totalRequests,
    requestsByStatus,
    totalPickups,
    pickupsByStatus,
    avgRating,
    recentDonations,
    donationsOverTime,
  ] = await Promise.all([
    User.countDocuments({ isActive: true }),

    User.aggregate([
      { $match: { isActive: true } },
      { $group: { _id: '$role', count: { $sum: 1 } } },
    ]),

    Donation.countDocuments(),

    Donation.aggregate([
      { $group: { _id: '$status', count: { $sum: 1 } } },
    ]),

    Donation.aggregate([
      { $group: { _id: '$foodType', count: { $sum: 1 } } },
      { $sort: { count: -1 } },
    ]),

    Request.countDocuments(),

    Request.aggregate([
      { $group: { _id: '$status', count: { $sum: 1 } } },
    ]),

    Pickup.countDocuments(),

    Pickup.aggregate([
      { $group: { _id: '$status', count: { $sum: 1 } } },
    ]),

    Feedback.aggregate([
      { $match: { isHidden: false } },
      { $group: { _id: null, avgRating: { $avg: '$rating' }, total: { $sum: 1 } } },
    ]),

    Donation.find({ createdAt: { $gte: daysAgo } })
      .sort({ createdAt: -1 })
      .limit(10)
      .select('foodName quantity status createdAt address'),

    // Donations per day for chart
    Donation.aggregate([
      { $match: { createdAt: { $gte: daysAgo } } },
      {
        $group: {
          _id: {
            year: { $year: '$createdAt' },
            month: { $month: '$createdAt' },
            day: { $dayOfMonth: '$createdAt' },
          },
          count: { $sum: 1 },
          totalQuantity: { $sum: '$quantity.value' },
        },
      },
      { $sort: { '_id.year': 1, '_id.month': 1, '_id.day': 1 } },
    ]),
  ]);

  // Calculate delivered/fulfilled donations
  const deliveredDonations = donationsByStatus.find((d) => d._id === 'delivered')?.count || 0;
  const wasteReduced = await Donation.aggregate([
    { $match: { status: 'delivered' } },
    { $group: { _id: null, totalKg: { $sum: '$quantity.value' } } },
  ]);

  res.status(200).json({
    success: true,
    data: {
      overview: {
        totalUsers,
        totalDonations,
        totalRequests,
        totalPickups,
        deliveredDonations,
        platformRating: avgRating[0]?.avgRating?.toFixed(1) || 0,
        totalFeedbacks: avgRating[0]?.total || 0,
        wasteReducedKg: wasteReduced[0]?.totalKg || 0,
      },
      usersByRole: usersByRole.reduce((acc, r) => ({ ...acc, [r._id]: r.count }), {}),
      donationsByStatus: donationsByStatus.reduce((acc, r) => ({ ...acc, [r._id]: r.count }), {}),
      donationsByFoodType,
      requestsByStatus: requestsByStatus.reduce((acc, r) => ({ ...acc, [r._id]: r.count }), {}),
      pickupsByStatus: pickupsByStatus.reduce((acc, r) => ({ ...acc, [r._id]: r.count }), {}),
      recentDonations,
      donationsOverTime,
      period: `${period} days`,
    },
  });
});

// ─── @route  GET /api/admin/donations ────────────────────────────────────────
const getAllDonations = asyncHandler(async (req, res) => {
  const page = Math.max(parseInt(req.query.page, 10) || 1, 1);
  const limit = Math.min(parseInt(req.query.limit, 10) || 20, 100);
  const skip = (page - 1) * limit;
  const { status, foodType, city } = req.query;

  const query = {};
  if (status) query.status = status;
  if (foodType) query.foodType = foodType;
  if (city) query['address.city'] = { $regex: city, $options: 'i' };

  const [donations, total] = await Promise.all([
    Donation.find(query).sort({ createdAt: -1 }).skip(skip).limit(limit),
    Donation.countDocuments(query),
  ]);

  res.status(200).json({
    success: true,
    data: { donations, pagination: { total, page, limit, pages: Math.ceil(total / limit) } },
  });
});

// ─── @route  PUT /api/admin/ngo/:id/verify ───────────────────────────────────
const verifyNgo = asyncHandler(async (req, res) => {
  const user = await User.findOne({ _id: req.params.id, role: 'ngo' });
  if (!user) throw new AppError('NGO not found.', 404);

  user.ngoDetails.verified = true;
  await user.save({ validateBeforeSave: false });

  res.status(200).json({ success: true, message: 'NGO verified.', data: { user } });
});

// ─── @route  GET /api/admin/dashboard-summary ───────────────────────────────
const getDashboardSummary = asyncHandler(async (req, res) => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const [todayDonations, pendingRequests, activePickups, newUsersToday] = await Promise.all([
    Donation.countDocuments({ createdAt: { $gte: today } }),
    Request.countDocuments({ status: 'pending' }),
    Pickup.countDocuments({ status: { $in: ['assigned', 'accepted', 'en_route_pickup', 'picked_up', 'en_route_delivery'] } }),
    User.countDocuments({ createdAt: { $gte: today } }),
  ]);

  res.status(200).json({
    success: true,
    data: { todayDonations, pendingRequests, activePickups, newUsersToday },
  });
});

module.exports = {
  getAllUsers,
  getUserById,
  updateUser,
  deactivateUser,
  getAnalytics,
  getAllDonations,
  verifyNgo,
  getDashboardSummary,
};

/**
 * Chat Controller
 * Message sending, retrieval, and conversation management
 */

const Message = require('../models/Message');
const User = require('../models/User');
const { asyncHandler, AppError } = require('../middleware/error');

// ─── @route  POST /api/messages ──────────────────────────────────────────────
const sendMessage = asyncHandler(async (req, res) => {
  const { receiverId, text, messageType, attachment, donationRef } = req.body;

  if (!text && !attachment) {
    throw new AppError('Message must have text or an attachment.', 400);
  }

  // Verify receiver exists
  const receiver = await User.findById(receiverId);
  if (!receiver) throw new AppError('Receiver not found.', 404);

  // Prevent messaging self
  if (receiverId === req.user._id.toString()) {
    throw new AppError('You cannot message yourself.', 400);
  }

  const message = await Message.create({
    senderId: req.user._id,
    receiverId,
    text,
    messageType: messageType || 'text',
    attachment,
    donationRef,
    status: 'sent',
  });

  // Real-time delivery via Socket.io
  const io = req.app.get('io');
  if (io) {
    const receiverSocketId = req.app.get('onlineUsers')?.[receiverId];
    if (receiverSocketId) {
      io.to(receiverSocketId).emit('message:received', {
        messageId: message._id,
        senderId: req.user._id,
        text,
        createdAt: message.createdAt,
      });
      // Mark as delivered
      await Message.findByIdAndUpdate(message._id, {
        status: 'delivered',
        deliveredAt: new Date(),
      });
    }
  }

  res.status(201).json({
    success: true,
    message: 'Message sent.',
    data: { message },
  });
});

// ─── @route  GET /api/messages/:userId ───────────────────────────────────────
const getConversation = asyncHandler(async (req, res) => {
  const otherUserId = req.params.userId;
  const page = Math.max(parseInt(req.query.page, 10) || 1, 1);
  const limit = Math.min(parseInt(req.query.limit, 10) || 50, 100);

  // Verify user exists
  const otherUser = await User.findById(otherUserId).select('name avatar role');
  if (!otherUser) throw new AppError('User not found.', 404);

  const messages = await Message.getConversation(req.user._id, otherUserId, page, limit);

  // Mark all received messages as read
  await Message.updateMany(
    {
      senderId: otherUserId,
      receiverId: req.user._id,
      status: { $ne: 'read' },
    },
    { status: 'read', readAt: new Date() }
  );

  // Notify sender that messages are read via socket
  const io = req.app.get('io');
  if (io) {
    io.to(`user_${otherUserId}`).emit('messages:read', {
      readBy: req.user._id,
    });
  }

  res.status(200).json({
    success: true,
    data: {
      messages: messages.reverse(), // oldest first
      otherUser,
      pagination: { page, limit },
    },
  });
});

// ─── @route  GET /api/messages ────────────────────────────────────────────────
const getConversationList = asyncHandler(async (req, res) => {
  const conversations = await Message.getConversationList(req.user._id);

  // Populate user details for each conversation
  const populatedConversations = await Promise.all(
    conversations.map(async (conv) => {
      const user = await User.findById(conv._id).select('name avatar role isActive');
      return { ...conv, user };
    })
  );

  res.status(200).json({
    success: true,
    data: { conversations: populatedConversations },
  });
});

// ─── @route  DELETE /api/messages/:id ────────────────────────────────────────
const deleteMessage = asyncHandler(async (req, res) => {
  const message = await Message.findById(req.params.id);
  if (!message) throw new AppError('Message not found.', 404);

  const senderId = message.senderId._id ? message.senderId._id.toString() : message.senderId.toString();
  const receiverId = message.receiverId._id ? message.receiverId._id.toString() : message.receiverId.toString();
  const userId = req.user._id.toString();

  if (senderId === userId) {
    message.deletedBySender = true;
  } else if (receiverId === userId) {
    message.deletedByReceiver = true;
  } else {
    throw new AppError('Not authorized to delete this message.', 403);
  }

  // Permanently delete if both parties deleted
  if (message.deletedBySender && message.deletedByReceiver) {
    await Message.findByIdAndDelete(req.params.id);
    return res.status(200).json({ success: true, message: 'Message permanently deleted.' });
  }

  await message.save();
  res.status(200).json({ success: true, message: 'Message deleted.' });
});

// ─── @route  GET /api/messages/unread/count ──────────────────────────────────
const getUnreadCount = asyncHandler(async (req, res) => {
  const count = await Message.countDocuments({
    receiverId: req.user._id,
    status: { $ne: 'read' },
    deletedByReceiver: false,
  });

  res.status(200).json({ success: true, data: { unreadCount: count } });
});

module.exports = { sendMessage, getConversation, getConversationList, deleteMessage, getUnreadCount };

/**
 * Donation Controller
 * CRUD + geo-based nearby donations
 */

const Donation = require('../models/Donation');
const Notification = require('../models/Notification');
const { asyncHandler, AppError } = require('../middleware/error');

// ─── Helper: pagination ───────────────────────────────────────────────────────
const getPagination = (query) => {
  const page = Math.max(parseInt(query.page, 10) || 1, 1);
  const limit = Math.min(parseInt(query.limit, 10) || 10, 100);
  const skip = (page - 1) * limit;
  return { page, limit, skip };
};

// ─── @route  POST /api/donations ─────────────────────────────────────────────
const createDonation = asyncHandler(async (req, res) => {
  const donationData = { ...req.body, donorId: req.user._id };

  // Set pickupWindowEnd to expiryTime if not provided
  if (!donationData.pickupWindowEnd) {
    donationData.pickupWindowEnd = donationData.expiryTime;
  }

  const donation = await Donation.create(donationData);

  // Emit socket event for real-time dashboard update
  const io = req.app.get('io');
  if (io) {
    io.emit('donation:new', {
      donationId: donation._id,
      foodName: donation.foodName,
      location: donation.location,
    });
  }

  res.status(201).json({
    success: true,
    message: 'Donation posted successfully.',
    data: { donation },
  });
});

// ─── @route  GET /api/donations ──────────────────────────────────────────────
const getDonations = asyncHandler(async (req, res) => {
  const { page, limit, skip } = getPagination(req.query);
  const {
    status,
    foodType,
    isVegetarian,
    city,
    lat,
    lng,
    radius = 10, // km
    sortBy = 'createdAt',
    order = 'desc',
  } = req.query;

  let query = {};

  // Filters
  if (status) query.status = status;
  if (foodType) query.foodType = foodType;
  if (isVegetarian !== undefined) query.isVegetarian = isVegetarian === 'true';
  if (city) query['address.city'] = { $regex: city, $options: 'i' };

  // Only donors see their own donations; NGOs/volunteers see all available
  if (req.user?.role === 'donor') {
    query.donorId = req.user._id;
  }

  let mongoQuery;

  // ─── Geo-based query (nearby donations) ───────────────────────────────────
  if (lat && lng) {
    mongoQuery = Donation.find({
      ...query,
      location: {
        $near: {
          $geometry: { type: 'Point', coordinates: [parseFloat(lng), parseFloat(lat)] },
          $maxDistance: parseFloat(radius) * 1000, // convert km to meters
        },
      },
    });
  } else {
    mongoQuery = Donation.find(query);
  }

  // Sorting
  const sortOrder = order === 'asc' ? 1 : -1;
  mongoQuery = mongoQuery.sort({ [sortBy]: sortOrder });

  // Execute with pagination
  const [donations, total] = await Promise.all([
    mongoQuery.skip(skip).limit(limit),
    Donation.countDocuments(query),
  ]);

  res.status(200).json({
    success: true,
    data: {
      donations,
      pagination: {
        total,
        page,
        limit,
        pages: Math.ceil(total / limit),
        hasNext: page * limit < total,
        hasPrev: page > 1,
      },
    },
  });
});

// ─── @route  GET /api/donations/:id ──────────────────────────────────────────
const getDonationById = asyncHandler(async (req, res) => {
  const donation = await Donation.findById(req.params.id);

  if (!donation) {
    throw new AppError('Donation not found.', 404);
  }

  res.status(200).json({
    success: true,
    data: { donation },
  });
});

// ─── @route  PUT /api/donations/:id ──────────────────────────────────────────
const updateDonation = asyncHandler(async (req, res) => {
  const donation = await Donation.findById(req.params.id);

  if (!donation) {
    throw new AppError('Donation not found.', 404);
  }

  // Only donor who created it or admin can update
  if (
    donation.donorId._id.toString() !== req.user._id.toString() &&
    req.user.role !== 'admin'
  ) {
    throw new AppError('You are not authorized to update this donation.', 403);
  }

  // Prevent editing if already picked up or delivered
  if (['picked_up', 'delivered'].includes(donation.status)) {
    throw new AppError('Cannot edit a donation that has been picked up or delivered.', 400);
  }

  const allowedFields = [
    'foodName', 'foodType', 'description', 'quantity', 'servingSize',
    'expiryTime', 'pickupWindowStart', 'pickupWindowEnd', 'location',
    'address', 'isVegetarian', 'isVegan', 'allergens', 'status',
    'cancelledReason', 'images',
  ];

  const updates = {};
  allowedFields.forEach((field) => {
    if (req.body[field] !== undefined) updates[field] = req.body[field];
  });

  const updated = await Donation.findByIdAndUpdate(req.params.id, updates, {
    new: true,
    runValidators: true,
  });

  // Notify if status changed to cancelled
  const io = req.app.get('io');
  if (io && updates.status === 'cancelled') {
    io.emit('donation:cancelled', { donationId: updated._id });
  }

  res.status(200).json({
    success: true,
    message: 'Donation updated successfully.',
    data: { donation: updated },
  });
});

// ─── @route  DELETE /api/donations/:id ───────────────────────────────────────
const deleteDonation = asyncHandler(async (req, res) => {
  const donation = await Donation.findById(req.params.id);

  if (!donation) {
    throw new AppError('Donation not found.', 404);
  }

  if (
    donation.donorId._id.toString() !== req.user._id.toString() &&
    req.user.role !== 'admin'
  ) {
    throw new AppError('You are not authorized to delete this donation.', 403);
  }

  if (['assigned', 'picked_up'].includes(donation.status)) {
    throw new AppError('Cannot delete a donation that is currently being processed.', 400);
  }

  await Donation.findByIdAndDelete(req.params.id);

  res.status(200).json({
    success: true,
    message: 'Donation deleted successfully.',
  });
});

// ─── @route  GET /api/donations/nearby ───────────────────────────────────────
const getNearbyDonations = asyncHandler(async (req, res) => {
  const { lat, lng, radius = 10 } = req.query;

  if (!lat || !lng) {
    throw new AppError('Latitude and longitude are required for nearby search.', 400);
  }

  const donations = await Donation.find({
    status: 'available',
    location: {
      $near: {
        $geometry: { type: 'Point', coordinates: [parseFloat(lng), parseFloat(lat)] },
        $maxDistance: parseFloat(radius) * 1000,
      },
    },
    expiryTime: { $gt: new Date() },
  }).limit(50);

  res.status(200).json({
    success: true,
    data: {
      donations,
      count: donations.length,
      searchRadius: `${radius} km`,
    },
  });
});

// ─── @route  GET /api/donations/my ───────────────────────────────────────────
const getMyDonations = asyncHandler(async (req, res) => {
