/**
 * Feedback Controller
 * Ratings and comments after donations/pickups
 */

const Feedback = require('../models/Feedback');
const User = require('../models/User');
const { asyncHandler, AppError } = require('../middleware/error');

// ─── @route  POST /api/feedback ──────────────────────────────────────────────
const createFeedback = asyncHandler(async (req, res) => {
  const { targetUserId, rating, comment, category, donationId, pickupId, tags, isAnonymous } = req.body;

  // Can't review yourself
  if (targetUserId === req.user._id.toString()) {
    throw new AppError('You cannot review yourself.', 400);
  }

  const targetUser = await User.findById(targetUserId);
  if (!targetUser) throw new AppError('Target user not found.', 404);

  const feedback = await Feedback.create({
    userId: req.user._id,
    targetUserId,
    rating,
    comment,
    category,
    donationId,
    pickupId,
    tags,
    isAnonymous: isAnonymous || false,
  });

  // Update volunteer average rating
  if (targetUser.role === 'volunteer') {
    const { avgRating } = await Feedback.getAverageRating(targetUser._id);
    await User.findByIdAndUpdate(targetUserId, {
      'volunteerDetails.rating': Math.round(avgRating * 10) / 10,
    });
  }

  res.status(201).json({
    success: true,
    message: 'Feedback submitted successfully.',
    data: { feedback },
  });
});

// ─── @route  GET /api/feedback ───────────────────────────────────────────────
const getFeedback = asyncHandler(async (req, res) => {
  const page = Math.max(parseInt(req.query.page, 10) || 1, 1);
  const limit = Math.min(parseInt(req.query.limit, 10) || 10, 100);
  const skip = (page - 1) * limit;
  const { targetUserId, category, minRating, maxRating } = req.query;

  const query = { isHidden: false };

  if (targetUserId) query.targetUserId = targetUserId;
  if (category) query.category = category;
  if (minRating || maxRating) {
    query.rating = {};
    if (minRating) query.rating.$gte = parseFloat(minRating);
    if (maxRating) query.rating.$lte = parseFloat(maxRating);
  }

  // Donors/NGOs/Volunteers only see feedback for themselves
  if (['donor', 'ngo', 'volunteer'].includes(req.user.role) && !targetUserId) {
    query.targetUserId = req.user._id;
  }

  const [feedbacks, total, stats] = await Promise.all([
    Feedback.find(query).sort({ createdAt: -1 }).skip(skip).limit(limit),
    Feedback.countDocuments(query),
    targetUserId
      ? Feedback.aggregate([
          { $match: { targetUserId: require('mongoose').Types.ObjectId.createFromHexString(targetUserId), isHidden: false } },
          {
            $group: {
              _id: null,
              avgRating: { $avg: '$rating' },
              count: { $sum: 1 },
              dist: { $push: '$rating' },
            },
          },
        ])
      : Promise.resolve([]),
  ]);

  res.status(200).json({
    success: true,
    data: {
      feedbacks,
      stats: stats[0] || { avgRating: 0, count: total },
      pagination: { total, page, limit, pages: Math.ceil(total / limit) },
    },
  });
});

// ─── @route  GET /api/feedback/:id ───────────────────────────────────────────
const getFeedbackById = asyncHandler(async (req, res) => {
  const feedback = await Feedback.findById(req.params.id);
  if (!feedback) throw new AppError('Feedback not found.', 404);

  res.status(200).json({ success: true, data: { feedback } });
});

// ─── @route  POST /api/feedback/:id/reply ────────────────────────────────────
const replyToFeedback = asyncHandler(async (req, res) => {
  const { text } = req.body;
  if (!text) throw new AppError('Reply text is required.', 400);

  const feedback = await Feedback.findById(req.params.id);
  if (!feedback) throw new AppError('Feedback not found.', 404);

  const targetId = feedback.targetUserId._id ? feedback.targetUserId._id.toString() : feedback.targetUserId.toString();
  if (targetId !== req.user._id.toString() && req.user.role !== 'admin') {
    throw new AppError('Only the reviewed user can reply.', 403);
  }

  feedback.reply = { text, repliedAt: new Date() };
  await feedback.save();

  res.status(200).json({ success: true, message: 'Reply added.', data: { feedback } });
});

// ─── @route  DELETE /api/feedback/:id (Admin only) ───────────────────────────
const hideFeedback = asyncHandler(async (req, res) => {
  const { reason } = req.body;
  const feedback = await Feedback.findByIdAndUpdate(
    req.params.id,
    { isHidden: true, hiddenReason: reason },
    { new: true }
  );
  if (!feedback) throw new AppError('Feedback not found.', 404);

  res.status(200).json({ success: true, message: 'Feedback hidden.', data: { feedback } });
});

module.exports = { createFeedback, getFeedback, getFeedbackById, replyToFeedback, hideFeedback };

/**
 * Pickup Controller
 * Assigns volunteers to donations and tracks pickup status
 */

const Pickup = require('../models/Pickup');
const Donation = require('../models/Donation');
const User = require('../models/User');
const Notification = require('../models/Notification');
const { asyncHandler, AppError } = require('../middleware/error');

// ─── @route  POST /api/pickup/assign ─────────────────────────────────────────
const assignPickup = asyncHandler(async (req, res) => {
  const { donationId, volunteerId, requestId, ngoId } = req.body;

  // Verify donation
  const donation = await Donation.findById(donationId);
  if (!donation) throw new AppError('Donation not found.', 404);
  if (!['available', 'assigned', 'requested'].includes(donation.status)) {
    throw new AppError(`Donation cannot be assigned. Status: ${donation.status}`, 400);
  }

  // Verify volunteer
  const volunteer = await User.findById(volunteerId);
  if (!volunteer || volunteer.role !== 'volunteer') {
    throw new AppError('Invalid volunteer.', 400);
  }
  if (!volunteer.volunteerDetails?.availability) {
    throw new AppError('Volunteer is not currently available.', 400);
  }

  // Check volunteer doesn't already have active pickup
  const activePickup = await Pickup.findOne({
    volunteerId,
    status: { $in: ['assigned', 'accepted', 'en_route_pickup', 'picked_up', 'en_route_delivery'] },
  });
  if (activePickup) {
    throw new AppError('Volunteer already has an active pickup task.', 409);
  }

  // Create pickup record
  const pickup = await Pickup.create({
    volunteerId,
    donationId,
    requestId: requestId || null,
    ngoId: ngoId || null,
    pickupLocation: donation.location,
    status: 'assigned',
  });

  // Update donation status
  await Donation.findByIdAndUpdate(donationId, {
    status: 'assigned',
    assignedVolunteer: volunteerId,
  });

  // Set volunteer unavailable
  await User.findByIdAndUpdate(volunteerId, {
    'volunteerDetails.availability': false,
  });

  // Notify volunteer
  await Notification.create({
    userId: volunteerId,
    type: 'pickup_assigned',
    title: 'New Pickup Task Assigned',
    body: `You have been assigned to pick up: ${donation.foodName}`,
    data: { pickupId: pickup._id, donationId },
    channels: ['in_app'],
  });

  const io = req.app.get('io');
  if (io) {
    io.to(`user_${volunteerId}`).emit('pickup:assigned', { pickupId: pickup._id });
  }

  res.status(201).json({
    success: true,
    message: 'Pickup assigned successfully.',
    data: { pickup },
  });
});

// ─── @route  PUT /api/pickup/status ──────────────────────────────────────────
const updatePickupStatus = asyncHandler(async (req, res) => {
  const { pickupId, status, notes, currentLocation } = req.body;

  const pickup = await Pickup.findById(pickupId);
  if (!pickup) throw new AppError('Pickup record not found.', 404);

  // Volunteers can only update their own pickups
  const volId = pickup.volunteerId._id ? pickup.volunteerId._id.toString() : pickup.volunteerId.toString();
  if (req.user.role === 'volunteer' && volId !== req.user._id.toString()) {
    throw new AppError('You can only update your own pickups.', 403);
  }

  // Status transition validation
  const validTransitions = {
    assigned: ['accepted', 'cancelled'],
    accepted: ['en_route_pickup', 'cancelled'],
    en_route_pickup: ['picked_up', 'failed'],
    picked_up: ['en_route_delivery'],
    en_route_delivery: ['delivered', 'failed'],
  };

  if (!validTransitions[pickup.status]?.includes(status)) {
    throw new AppError(
      `Invalid status transition: ${pickup.status} → ${status}. Allowed: ${validTransitions[pickup.status]?.join(', ')}`,
      400
    );
  }

  // Build update
  const updates = { status, notes };

  if (status === 'accepted') updates.acceptedAt = new Date();
  if (status === 'picked_up') {
    updates.pickedUpAt = new Date();
    // Update donation status
    await Donation.findByIdAndUpdate(pickup.donationId, { status: 'picked_up' });
  }
  if (status === 'delivered') {
    updates.deliveredAt = new Date();
    await Donation.findByIdAndUpdate(pickup.donationId, { status: 'delivered' });
    // Free volunteer
    await User.findByIdAndUpdate(pickup.volunteerId, {
      'volunteerDetails.availability': true,
      $inc: { 'volunteerDetails.totalPickups': 1 },
    });
  }
  if (['failed', 'cancelled'].includes(status)) {
    // Free the volunteer and revert donation
    await User.findByIdAndUpdate(pickup.volunteerId, { 'volunteerDetails.availability': true });
    await Donation.findByIdAndUpdate(pickup.donationId, {
      status: 'available',
      assignedVolunteer: null,
    });
    if (req.body.failureReason) updates.failureReason = req.body.failureReason;
  }

  if (currentLocation) {
    updates.currentLocation = currentLocation;
    updates.updatedByVolunteer = new Date();
  }

  const updated = await Pickup.findByIdAndUpdate(pickupId, updates, { new: true });

  // Emit real-time tracking update
  const io = req.app.get('io');
  if (io) {
    io.emit(`pickup:update:${pickupId}`, { status, currentLocation });

    if (status === 'delivered') {
      const ngoId = pickup.ngoId?._id || pickup.ngoId;
      if (ngoId) {
        await Notification.create({
          userId: ngoId,
          type: 'pickup_completed',
          title: 'Donation Delivered!',
          body: `Your donation pickup has been successfully delivered.`,
          data: { pickupId: pickup._id },
          channels: ['in_app'],
        });
        io.to(`user_${ngoId}`).emit('notification:new', { type: 'pickup_completed' });
      }
    }
  }

  res.status(200).json({
    success: true,
    message: `Pickup status updated to '${status}'.`,
    data: { pickup: updated },
  });
});

// ─── @route  GET /api/pickup ──────────────────────────────────────────────────
const getPickups = asyncHandler(async (req, res) => {
  const page = Math.max(parseInt(req.query.page, 10) || 1, 1);
  const limit = Math.min(parseInt(req.query.limit, 10) || 10, 100);
  const skip = (page - 1) * limit;
  const { status } = req.query;

  let query = {};
  if (req.user.role === 'volunteer') query.volunteerId = req.user._id;
  if (status) query.status = status;

  const [pickups, total] = await Promise.all([
    Pickup.find(query).sort({ createdAt: -1 }).skip(skip).limit(limit),
    Pickup.countDocuments(query),
  ]);

  res.status(200).json({
    success: true,
    data: { pickups, pagination: { total, page, limit, pages: Math.ceil(total / limit) } },
  });
});

// ─── @route  GET /api/pickup/:id ─────────────────────────────────────────────
const getPickupById = asyncHandler(async (req, res) => {
  const pickup = await Pickup.findById(req.params.id);
  if (!pickup) throw new AppError('Pickup not found.', 404);

  res.status(200).json({ success: true, data: { pickup } });
});

// ─── @route  GET /api/pickup/nearby-volunteers ────────────────────────────────
const getNearbyVolunteers = asyncHandler(async (req, res) => {
  const { lat, lng, radius = 15 } = req.query;

  if (!lat || !lng) throw new AppError('Latitude and longitude are required.', 400);

  const volunteers = await User.find({
    role: 'volunteer',
    isActive: true,
    'volunteerDetails.availability': true,
    location: {
      $near: {
        $geometry: { type: 'Point', coordinates: [parseFloat(lng), parseFloat(lat)] },
        $maxDistance: parseFloat(radius) * 1000,
      },
    },
  }).select('name email phone volunteerDetails location address');

  res.status(200).json({
    success: true,
    data: { volunteers, count: volunteers.length },
  });
});

module.exports = { assignPickup, updatePickupStatus, getPickups, getPickupById, getNearbyVolunteers };

/**
 * Request Controller
 * NGO requests to claim donations
 */

const Request = require('../models/Request');
const Donation = require('../models/Donation');
const Notification = require('../models/Notification');
const { asyncHandler, AppError } = require('../middleware/error');

const getPagination = (q) => {
  const page = Math.max(parseInt(q.page, 10) || 1, 1);
  const limit = Math.min(parseInt(q.limit, 10) || 10, 100);
  return { page, limit, skip: (page - 1) * limit };
};

// ─── @route  POST /api/requests ──────────────────────────────────────────────
const createRequest = asyncHandler(async (req, res) => {
  const { donationId, message, urgencyLevel, requiredBy, beneficiaryCount } = req.body;

  // Verify donation exists and is available
  const donation = await Donation.findById(donationId);
  if (!donation) throw new AppError('Donation not found.', 404);
  if (donation.status !== 'available') {
    throw new AppError(`Donation is not available. Current status: ${donation.status}`, 400);
  }
  if (new Date() > donation.expiryTime) {
    throw new AppError('This donation has expired.', 400);
  }

  // Check for duplicate pending/approved request
  const existing = await Request.findOne({
    ngoId: req.user._id,
    donationId,
    status: { $in: ['pending', 'approved'] },
  });
  if (existing) {
    throw new AppError('You have already submitted a request for this donation.', 409);
  }

  const request = await Request.create({
    ngoId: req.user._id,
    donationId,
    message,
    urgencyLevel,
    requiredBy,
    beneficiaryCount,
  });

  // Update donation status to requested
  await Donation.findByIdAndUpdate(donationId, { status: 'requested' });

  // Notify donor
  await Notification.create({
    userId: donation.donorId._id || donation.donorId,
    type: 'donation_requested',
    title: 'New Request for Your Donation',
    body: `${req.user.name} has requested your donation: ${donation.foodName}`,
    data: { donationId, requestId: request._id },
    channels: ['in_app'],
  });

  // Socket.io - real-time notification
  const io = req.app.get('io');
  if (io) {
    io.to(`user_${donation.donorId}`).emit('notification:new', {
      type: 'donation_requested',
      requestId: request._id,
    });
  }

  res.status(201).json({
    success: true,
    message: 'Request submitted successfully.',
    data: { request },
  });
});

// ─── @route  GET /api/requests ───────────────────────────────────────────────
const getRequests = asyncHandler(async (req, res) => {
  const { page, limit, skip } = getPagination(req.query);
  const { status, donationId } = req.query;

  let query = {};

  // Role-based filtering
  if (req.user.role === 'ngo') {
    query.ngoId = req.user._id;
  } else if (req.user.role === 'donor') {
    // Find donations by this donor
    const myDonations = await Donation.find({ donorId: req.user._id }).select('_id');
    query.donationId = { $in: myDonations.map((d) => d._id) };
  }
  // Admin sees all

  if (status) query.status = status;
  if (donationId) query.donationId = donationId;

  const [requests, total] = await Promise.all([
    Request.find(query).sort({ createdAt: -1 }).skip(skip).limit(limit),
    Request.countDocuments(query),
  ]);

  res.status(200).json({
    success: true,
    data: {
      requests,
      pagination: { total, page, limit, pages: Math.ceil(total / limit) },
    },
  });
});

// ─── @route  GET /api/requests/:id ───────────────────────────────────────────
const getRequestById = asyncHandler(async (req, res) => {
  const request = await Request.findById(req.params.id);
  if (!request) throw new AppError('Request not found.', 404);

  res.status(200).json({ success: true, data: { request } });
});

// ─── @route  PUT /api/requests/:id/approve ───────────────────────────────────
const approveRequest = asyncHandler(async (req, res) => {
  const request = await Request.findById(req.params.id);
  if (!request) throw new AppError('Request not found.', 404);

  if (request.status !== 'pending') {
    throw new AppError(`Request is already ${request.status}.`, 400);
  }

  // Verify the logged-in user is the donor who owns the donation
  const donation = await Donation.findById(request.donationId._id || request.donationId);
  const donorId = donation.donorId._id ? donation.donorId._id.toString() : donation.donorId.toString();
  if (donorId !== req.user._id.toString() && req.user.role !== 'admin') {
    throw new AppError('Only the donor or admin can approve requests.', 403);
  }

  request.status = 'approved';
  request.approvedAt = new Date();
  await request.save();

  // Update donation allocation
  await Donation.findByIdAndUpdate(donation._id, {
    status: 'assigned',
    allocatedTo: request.ngoId._id || request.ngoId,
  });

  // Reject other pending requests for same donation
  await Request.updateMany(
    { donationId: donation._id, status: 'pending', _id: { $ne: request._id } },
    { status: 'rejected', rejectionReason: 'Another request was approved.' }
  );

  // Notify NGO
  await Notification.create({
    userId: request.ngoId._id || request.ngoId,
    type: 'request_approved',
    title: 'Your Request was Approved!',
    body: `Your request for ${donation.foodName} has been approved. Please arrange pickup.`,
    data: { donationId: donation._id, requestId: request._id },
    channels: ['in_app'],
  });

  const io = req.app.get('io');
  if (io) {
    io.to(`user_${request.ngoId}`).emit('notification:new', {
      type: 'request_approved',
      requestId: request._id,
    });
  }

  res.status(200).json({
    success: true,
    message: 'Request approved successfully.',
    data: { request },
  });
});

// ─── @route  PUT /api/requests/:id/reject ────────────────────────────────────
const rejectRequest = asyncHandler(async (req, res) => {
  const { rejectionReason } = req.body;
  const request = await Request.findById(req.params.id);
  if (!request) throw new AppError('Request not found.', 404);

  const donation = await Donation.findById(request.donationId._id || request.donationId);
  const donorId = donation.donorId._id ? donation.donorId._id.toString() : donation.donorId.toString();
  if (donorId !== req.user._id.toString() && req.user.role !== 'admin') {
    throw new AppError('Only the donor or admin can reject requests.', 403);
  }

  request.status = 'rejected';
  request.rejectionReason = rejectionReason || 'No reason provided.';
  request.rejectedAt = new Date();
  await request.save();

  // If no other pending requests, set donation back to available
  const pendingCount = await Request.countDocuments({
    donationId: donation._id,
    status: 'pending',
  });
  if (pendingCount === 0 && donation.status === 'requested') {
    await Donation.findByIdAndUpdate(donation._id, { status: 'available', allocatedTo: null });
  }

  await Notification.create({
    userId: request.ngoId._id || request.ngoId,
    type: 'request_rejected',
    title: 'Request Update',
    body: `Your request for ${donation.foodName} was not approved.`,
    data: { requestId: request._id },
    channels: ['in_app'],
  });

  res.status(200).json({
    success: true,
    message: 'Request rejected.',
    data: { request },
  });
});

// ─── @route  PUT /api/requests/:id/cancel ────────────────────────────────────
const cancelRequest = asyncHandler(async (req, res) => {
  const request = await Request.findById(req.params.id);
  if (!request) throw new AppError('Request not found.', 404);

  const ngoId = request.ngoId._id ? request.ngoId._id.toString() : request.ngoId.toString();
  if (ngoId !== req.user._id.toString() && req.user.role !== 'admin') {
    throw new AppError('Only the requesting NGO can cancel.', 403);
  }

  if (!['pending', 'approved'].includes(request.status)) {
    throw new AppError('Cannot cancel a request that is already fulfilled or rejected.', 400);
  }

  request.status = 'cancelled';
  await request.save();

  // Revert donation status
  await Donation.findByIdAndUpdate(request.donationId, {
    status: 'available',
    allocatedTo: null,
  });

  res.status(200).json({
    success: true,
    message: 'Request cancelled.',
    data: { request },
  });
});

module.exports = {
  createRequest,
  getRequests,
  getRequestById,
  approveRequest,
  rejectRequest,
  cancelRequest,
};

/**
 * Global Error Handling Middleware
 * Catches all errors and returns consistent JSON responses
 */

const logger = require('../config/logger');

/**
 * Custom AppError class for operational errors
 */
class AppError extends Error {
  constructor(message, statusCode) {
    super(message);
    this.statusCode = statusCode;
    this.status = `${statusCode}`.startsWith('4') ? 'fail' : 'error';
    this.isOperational = true; // Distinguishes from programming errors
    Error.captureStackTrace(this, this.constructor);
  }
}

/**
 * Async handler wrapper - eliminates try/catch boilerplate
 * Usage: router.get('/path', asyncHandler(async (req, res) => { ... }))
 */
const asyncHandler = (fn) => (req, res, next) => {
  Promise.resolve(fn(req, res, next)).catch(next);
};

// ─── Specific error handlers ───────────────────────────────────────────────

const handleCastError = (err) => {
  const message = `Invalid ${err.path}: ${err.value}`;
  return new AppError(message, 400);
};

const handleDuplicateKeyError = (err) => {
  const field = Object.keys(err.keyValue)[0];
  const value = err.keyValue[field];
  const message = `Duplicate value for field '${field}': '${value}'. Please use a different value.`;
  return new AppError(message, 409);
};

const handleValidationError = (err) => {
  const errors = Object.values(err.errors).map((el) => el.message);
  const message = `Validation failed: ${errors.join('. ')}`;
  return new AppError(message, 400);
};

const handleJWTError = () =>
  new AppError('Invalid token. Please log in again.', 401);

const handleJWTExpiredError = () =>
  new AppError('Token expired. Please log in again.', 401);

// ─── Development error response (full stack trace) ─────────────────────────
const sendErrorDev = (err, res) => {
  res.status(err.statusCode || 500).json({
    success: false,
    status: err.status,
    message: err.message,
    stack: err.stack,
    error: err,
  });
};

// ─── Production error response (clean messages only) ──────────────────────
const sendErrorProd = (err, res) => {
  // Operational (trusted) errors - send to client
  if (err.isOperational) {
    return res.status(err.statusCode).json({
      success: false,
      status: err.status,
      message: err.message,
    });
  }

  // 5xx programming errors - don't leak details
  logger.error('UNHANDLED ERROR:', err);
  return res.status(500).json({
    success: false,
    status: 'error',
    message: 'Something went wrong. Please try again later.',
  });
};

// ─── Main error handler middleware ─────────────────────────────────────────
const errorHandler = (err, req, res, next) => {
  err.statusCode = err.statusCode || 500;
  err.status = err.status || 'error';

  // Log all errors
  logger.error({
    message: err.message,
    stack: err.stack,
    url: req.originalUrl,
    method: req.method,
    ip: req.ip,
    userId: req.user?._id,
  });

  if (process.env.NODE_ENV === 'development') {
    return sendErrorDev(err, res);
  }

  // Transform known Mongoose/JWT errors into AppErrors for production
  let error = { ...err };
  error.message = err.message;

  if (err.name === 'CastError') error = handleCastError(err);
  if (err.code === 11000) error = handleDuplicateKeyError(err);
  if (err.name === 'ValidationError') error = handleValidationError(err);
  if (err.name === 'JsonWebTokenError') error = handleJWTError();
  if (err.name === 'TokenExpiredError') error = handleJWTExpiredError();

  return sendErrorProd(error, res);
};

/**
 * 404 Not Found handler - catch unmatched routes
 */
const notFound = (req, res, next) => {
  next(new AppError(`Route not found: ${req.method} ${req.originalUrl}`, 404));
};

module.exports = { errorHandler, notFound, AppError, asyncHandler };

/**
 * Multer Upload Middleware
 * Handles multipart/form-data file uploads for donation images and user avatars
 */

const multer = require('multer');
const path = require('path');
const fs = require('fs');
const { AppError } = require('./error');

// ─── Ensure upload directories exist ─────────────────────────────────────────
const uploadDir = path.join(__dirname, '../uploads');
const dirs = [
  path.join(uploadDir, 'donations'),
  path.join(uploadDir, 'avatars'),
];
dirs.forEach((dir) => {
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
});

// ─── Storage Engine ───────────────────────────────────────────────────────────
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    // Route-based directory
    const isAvatar = req.baseUrl.includes('users') || req.path.includes('avatar');
    const dest = isAvatar
      ? path.join(uploadDir, 'avatars')
      : path.join(uploadDir, 'donations');
    cb(null, dest);
  },
  filename: (req, file, cb) => {
    const uniqueSuffix = `${Date.now()}-${Math.round(Math.random() * 1e9)}`;
    const ext = path.extname(file.originalname).toLowerCase();
    const userId = req.user?._id || 'unknown';
    cb(null, `${userId}-${uniqueSuffix}${ext}`);
  },
});

// ─── File Filter ──────────────────────────────────────────────────────────────
const fileFilter = (req, file, cb) => {
  const allowedMimes = ['image/jpeg', 'image/png', 'image/webp', 'image/gif'];
  if (allowedMimes.includes(file.mimetype)) {
    cb(null, true);
  } else {
    cb(new AppError(`Invalid file type: ${file.mimetype}. Only JPEG, PNG, WebP and GIF are allowed.`, 400), false);
  }
};

// ─── Multer instance ──────────────────────────────────────────────────────────
const maxSizeMB = parseInt(process.env.UPLOAD_MAX_SIZE_MB, 10) || 5;

const upload = multer({
  storage,
  fileFilter,
  limits: {
    fileSize: maxSizeMB * 1024 * 1024, // Convert MB to bytes
    files: 5, // Max 5 files per request
  },
});

// ─── Multer error handler ─────────────────────────────────────────────────────
const handleMulterError = (err, req, res, next) => {
  if (err instanceof multer.MulterError) {
    if (err.code === 'LIMIT_FILE_SIZE') {
      return next(new AppError(`File too large. Maximum allowed size is ${maxSizeMB}MB.`, 400));
    }
    if (err.code === 'LIMIT_FILE_COUNT') {
      return next(new AppError('Too many files. Maximum 5 files per upload.', 400));
    }
    return next(new AppError(`Upload error: ${err.message}`, 400));
  }
  next(err);
};

// ─── Convenience upload presets ───────────────────────────────────────────────
const uploadDonationImages = upload.array('images', 5);
const uploadAvatar = upload.single('avatar');

// ─── Generate public URL from file path ──────────────────────────────────────
const getFileUrl = (req, filePath) => {
  if (!filePath) return null;
  const relativePath = filePath.replace(path.join(__dirname, '..'), '').replace(/\\/g, '/');
  return `${req.protocol}://${req.get('host')}${relativePath}`;
};

module.exports = { upload, uploadDonationImages, uploadAvatar, handleMulterError, getFileUrl };

/**
 * Admin Routes
 * GET  /api/admin/dashboard-summary  - Dashboard KPIs
 * GET  /api/admin/analytics          - Full analytics
 * GET  /api/admin/users              - All users
 * GET  /api/admin/users/:id          - User by ID
 * PUT  /api/admin/users/:id          - Update user
 * DELETE /api/admin/users/:id        - Deactivate user
 * GET  /api/admin/donations          - All donations
 * PUT  /api/admin/ngo/:id/verify     - Verify NGO
 */

const express = require('express');
const router = express.Router();
const {
  getAllUsers,
  getUserById,
  updateUser,
  deactivateUser,
  getAnalytics,
  getAllDonations,
  verifyNgo,
  getDashboardSummary,
} = require('../controllers/adminController');
const { protect, authorize } = require('../middleware/auth');
const { mongoIdParam } = require('../middleware/validate');

// All admin routes require authentication + admin role
router.use(protect, authorize('admin'));

router.get('/dashboard-summary', getDashboardSummary);
router.get('/analytics', getAnalytics);

router.get('/users', getAllUsers);
router.get('/users/:id', mongoIdParam('id'), getUserById);
router.put('/users/:id', mongoIdParam('id'), updateUser);
router.delete('/users/:id', mongoIdParam('id'), deactivateUser);

router.get('/donations', getAllDonations);

router.put('/ngo/:id/verify', mongoIdParam('id'), verifyNgo);

module.exports = router;

/**
 * Matching Routes
 * GET  /api/matching/nearby      - Find nearest NGOs/volunteers for a donation
 * POST /api/matching/auto-assign - Auto-assign best volunteer to a donation
 * GET  /api/matching/stats       - Area-wise matching statistics
 * GET  /api/matching/score       - Explain match scores for a donation
 */

const express = require('express');
const router = express.Router();
const {
  getNearbyMatches,
  autoAssign,
  getStats,
  getMatchScore,
} = require('../controllers/matchingController');
const { protect, authorize } = require('../middleware/auth');

router.use(protect);

router.get('/nearby', getNearbyMatches);                          // All authenticated
router.post('/auto-assign', authorize('admin', 'donor', 'ngo'), autoAssign);
router.get('/stats', authorize('admin', 'ngo'), getStats);
router.get('/score', getNearbyMatches);

module.exports = router;

/**
 * ╔══════════════════════════════════════════════════════════════════════╗
 * ║     🍱  Food Donation & Redistribution System — Backend v2.0        ║
 * ║     Node.js · Express.js · MongoDB Atlas · Socket.io                ║
 * ╠══════════════════════════════════════════════════════════════════════╣
 * ║  Modules: Auth · Donations · NGO · Volunteer · Admin                ║
 * ║           Location · Notifications · Analytics · Matching           ║
 * ║           Real-time Chat · Feedback · File Upload                   ║
 * ╚══════════════════════════════════════════════════════════════════════╝
 */

require('dotenv').config();

const express   = require('express');
const http      = require('http');
const { Server }= require('socket.io');
const cors      = require('cors');
const helmet    = require('helmet');
const morgan    = require('morgan');
const path      = require('path');
const fs        = require('fs');

// ── Config ─────────────────────────────────────────────────────────────────
const connectDB           = require('./config/db');
const logger              = require('./config/logger');
const { initSockets }     = require('./sockets/index');
const initCronJobs        = require('./config/cron');
const { setupSwagger }    = require('./config/swagger');

// ── Rate Limiters ──────────────────────────────────────────────────────────
const { globalLimiter, authLimiter, messageLimiter } = require('./middleware/rateLimiter');

// ── Routes ─────────────────────────────────────────────────────────────────
const authRoutes         = require('./routes/authRoutes');
const userRoutes         = require('./routes/userRoutes');
const donationRoutes     = require('./routes/donationRoutes');
const requestRoutes      = require('./routes/requestRoutes');
const pickupRoutes       = require('./routes/pickupRoutes');
const chatRoutes         = require('./routes/chatRoutes');
const feedbackRoutes     = require('./routes/feedbackRoutes');
const notificationRoutes = require('./routes/notificationRoutes');
const adminRoutes        = require('./routes/adminRoutes');
const matchingRoutes     = require('./routes/matchingRoutes');

// ── Error Middleware ────────────────────────────────────────────────────────
const { errorHandler, notFound } = require('./middleware/error');

// ── Ensure required directories exist ──────────────────────────────────────
['logs', 'uploads/donations', 'uploads/avatars'].forEach((dir) => {
  const fullPath = path.join(__dirname, dir);
  if (!fs.existsSync(fullPath)) fs.mkdirSync(fullPath, { recursive: true });
});

// ── Initialize Express ──────────────────────────────────────────────────────
const app        = express();
const httpServer = http.createServer(app);

// ── Socket.io ───────────────────────────────────────────────────────────────
const io = new Server(httpServer, {
  cors: {
    origin     : process.env.SOCKET_CORS_ORIGIN || 'http://localhost:5173',
    methods    : ['GET', 'POST'],
    credentials: true,
  },
  pingTimeout : 60000,
  pingInterval: 25000,
});

const onlineUsers = initSockets(io);

// Make io & onlineUsers accessible inside controllers via req.app.get()
app.set('io', io);
app.set('onlineUsers', onlineUsers);

// ── Security Middleware ─────────────────────────────────────────────────────
app.use(
  helmet({
    crossOriginResourcePolicy: { policy: 'cross-origin' }, // allow serving uploads
  })
);

app.use(
  cors({
    origin     : process.env.CLIENT_URL || 'http://localhost:5173',
    credentials: true,
    methods    : ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization'],
  })
);

// ── Rate Limiting ───────────────────────────────────────────────────────────
app.use('/api/', globalLimiter);
app.use('/api/auth/login',    authLimiter);
app.use('/api/auth/register', authLimiter);
app.use('/api/messages',      messageLimiter);

// ── Body Parsing ────────────────────────────────────────────────────────────
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ extended: true, limit: '10mb' }));

// ── Static Files — uploaded images ─────────────────────────────────────────
app.use('/uploads', express.static(path.join(__dirname, 'uploads')));

// ── HTTP Logging ────────────────────────────────────────────────────────────
if (process.env.NODE_ENV !== 'test') {
  app.use(
    morgan('combined', {
      stream: { write: (msg) => logger.http(msg.trim()) },
    })
  );
}

// ── Swagger API Docs ────────────────────────────────────────────────────────
setupSwagger(app); // Mounts at /api/docs (only if SWAGGER_ENABLED=true)

// ── Health Check ────────────────────────────────────────────────────────────
/**
 * @swagger
 * /health:
 *   get:
 *     summary: Server health check
 *     tags: [System]
 *     security: []
 *     responses:
 *       200:
 *         description: Server is healthy
 */
app.get('/health', (req, res) => {
  res.status(200).json({
    success    : true,
    status     : 'healthy',
    environment: process.env.NODE_ENV,
    timestamp  : new Date().toISOString(),
    uptime     : `${Math.floor(process.uptime())}s`,
    socketConnections: io.engine.clientsCount,
  });
});

// ── API Info ────────────────────────────────────────────────────────────────
app.get('/api', (req, res) => {
  res.status(200).json({
    success: true,
    name   : '🍱 Food Donation & Redistribution API',
    version: '2.0.0',
    docs   : `${req.protocol}://${req.get('host')}/api/docs`,
    health : `${req.protocol}://${req.get('host')}/health`,
    endpoints: {
      auth        : '/api/auth',
      users       : '/api/users',
      donations   : '/api/donations',
      requests    : '/api/requests',
      pickup      : '/api/pickup',
      matching    : '/api/matching',
      messages    : '/api/messages',
      feedback    : '/api/feedback',
      notifications: '/api/notifications',
      admin       : '/api/admin',
    },
  });
});

// ── API Routes ──────────────────────────────────────────────────────────────
app.use('/api/auth',          authRoutes);
app.use('/api/users',         userRoutes);
app.use('/api/donations',     donationRoutes);
app.use('/api/requests',      requestRoutes);
app.use('/api/pickup',        pickupRoutes);
app.use('/api/matching',      matchingRoutes);
app.use('/api/messages',      chatRoutes);
app.use('/api/feedback',      feedbackRoutes);
app.use('/api/notifications', notificationRoutes);
app.use('/api/admin',         adminRoutes);

// ── 404 Handler ─────────────────────────────────────────────────────────────
app.use(notFound);

// ── Global Error Handler ─────────────────────────────────────────────────────
app.use(errorHandler);

// ── Start Server ─────────────────────────────────────────────────────────────
const PORT = process.env.PORT || 5000;

const startServer = async () => {
  try {
    await connectDB(); // Connect to MongoDB Atlas

    httpServer.listen(PORT, () => {
      logger.info(`
╔═══════════════════════════════════════════════════════════╗
║  🍱  Food Donation & Redistribution System — v2.0         ║
║  🌐  API:    http://localhost:${PORT}/api                    ║
║  📚  Docs:   http://localhost:${PORT}/api/docs               ║
║  💚  Health: http://localhost:${PORT}/health                 ║
║  🔌  Socket.io: enabled                                    ║
║  📦  Environment: ${(process.env.NODE_ENV || 'development').padEnd(12)}                    ║
║  🗄️  Database: MongoDB Atlas                               ║
╚═══════════════════════════════════════════════════════════╝`
      );
    });

    initCronJobs(); // Start scheduled auto-expire jobs

  } catch (error) {
    logger.error(`❌ Server failed to start: ${error.message}`);
    process.exit(1);
  }
};

// ── Graceful Shutdown ────────────────────────────────────────────────────────
const gracefulShutdown = (signal) => {
  logger.info(`\n${signal} received — shutting down gracefully...`);
  httpServer.close(async () => {
    const mongoose = require('mongoose');
    await mongoose.connection.close();
    logger.info('✅ MongoDB connection closed. Server stopped.');
    process.exit(0);
  });
  setTimeout(() => { logger.error('⏰ Forced shutdown.'); process.exit(1); }, 10000);
};

process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));
process.on('SIGINT',  () => gracefulShutdown('SIGINT'));

process.on('unhandledRejection', (reason) => {
  logger.error('Unhandled Rejection:', reason);
});
process.on('uncaughtException', (error) => {
  logger.error('Uncaught Exception:', error);
  process.exit(1);
});

startServer();

module.exports = { app, httpServer }; // Export for Jest tests

/**
 * Analytics Service
 * Complex aggregation pipelines for platform analytics
 */

const Donation = require('../models/Donation');
const User = require('../models/User');
const Request = require('../models/Request');
const Pickup = require('../models/Pickup');
const Feedback = require('../models/Feedback');

/**
 * Get comprehensive platform analytics
 * @param {number} days - number of days to look back
 */
const getPlatformAnalytics = async (days = 30) => {
  const since = new Date(Date.now() - days * 24 * 60 * 60 * 1000);

  const [
    userStats,
    donationStats,
    donationByStatus,
    donationByFoodType,
    areaWiseDistribution,
    requestStats,
    pickupStats,
    ratingStats,
    donationsOverTime,
    topDonors,
    topNGOs,
    wasteReduced,
  ] = await Promise.all([

    // ── User stats ──────────────────────────────────────────────────────────
    User.aggregate([
      {
        $group: {
          _id: '$role',
          count: { $sum: 1 },
          active: { $sum: { $cond: ['$isActive', 1, 0] } },
        },
      },
    ]),

    // ── Donation totals ──────────────────────────────────────────────────────
    Donation.aggregate([
      {
        $group: {
          _id: null,
          total: { $sum: 1 },
          thisMonth: {
            $sum: { $cond: [{ $gte: ['$createdAt', since] }, 1, 0] },
          },
          totalQuantityKg: {
            $sum: {
              $cond: [{ $eq: ['$quantity.unit', 'kg'] }, '$quantity.value', 0],
            },
          },
          avgServingSize: { $avg: '$servingSize' },
        },
      },
    ]),

    // ── Donations by status ──────────────────────────────────────────────────
    Donation.aggregate([
      { $group: { _id: '$status', count: { $sum: 1 } } },
    ]),

    // ── Donations by food type ───────────────────────────────────────────────
    Donation.aggregate([
      { $group: { _id: '$foodType', count: { $sum: 1 } } },
      { $sort: { count: -1 } },
      { $limit: 10 },
    ]),

    // ── Area-wise donation distribution ──────────────────────────────────────
    Donation.aggregate([
      {
        $group: {
          _id: '$address.city',
          total: { $sum: 1 },
          delivered: { $sum: { $cond: [{ $eq: ['$status', 'delivered'] }, 1, 0] } },
          available: { $sum: { $cond: [{ $eq: ['$status', 'available'] }, 1, 0] } },
        },
      },
      { $match: { _id: { $ne: null } } },
      { $sort: { total: -1 } },
      { $limit: 15 },
    ]),

    // ── Request stats ────────────────────────────────────────────────────────
    Request.aggregate([
      {
        $group: {
          _id: '$status',
          count: { $sum: 1 },
        },
      },
    ]),

    // ── Pickup stats ─────────────────────────────────────────────────────────
    Pickup.aggregate([
      {
        $group: {
          _id: '$status',
          count: { $sum: 1 },
        },
      },
    ]),

    // ── Platform rating ──────────────────────────────────────────────────────
    Feedback.aggregate([
      { $match: { isHidden: false } },
      {
        $group: {
          _id: '$category',
          avgRating: { $avg: '$rating' },
          count: { $sum: 1 },
        },
      },
    ]),

    // ── Donations over time (daily chart data) ───────────────────────────────
    Donation.aggregate([
      { $match: { createdAt: { $gte: since } } },
      {
        $group: {
          _id: {
            year: { $year: '$createdAt' },
            month: { $month: '$createdAt' },
            day: { $dayOfMonth: '$createdAt' },
          },
          count: { $sum: 1 },
          delivered: {
            $sum: { $cond: [{ $eq: ['$status', 'delivered'] }, 1, 0] },
          },
        },
      },
      { $sort: { '_id.year': 1, '_id.month': 1, '_id.day': 1 } },
      {
        $project: {
          date: {
            $dateFromParts: {
              year: '$_id.year',
              month: '$_id.month',
              day: '$_id.day',
            },
          },
          count: 1,
          delivered: 1,
          _id: 0,
        },
      },
    ]),

    // ── Top 5 donors ─────────────────────────────────────────────────────────
    Donation.aggregate([
      { $match: { status: { $in: ['delivered', 'picked_up'] } } },
      { $group: { _id: '$donorId', donations: { $sum: 1 } } },
      { $sort: { donations: -1 } },
      { $limit: 5 },
      {
        $lookup: {
          from: 'users',
          localField: '_id',
          foreignField: '_id',
          as: 'donor',
        },
      },
      { $unwind: '$donor' },
      { $project: { name: '$donor.name', email: '$donor.email', donations: 1 } },
    ]),

    // ── Top 5 NGOs ───────────────────────────────────────────────────────────
    Request.aggregate([
      { $match: { status: 'fulfilled' } },
      { $group: { _id: '$ngoId', fulfilled: { $sum: 1 } } },
      { $sort: { fulfilled: -1 } },
      { $limit: 5 },
      {
        $lookup: {
          from: 'users',
          localField: '_id',
          foreignField: '_id',
          as: 'ngo',
        },
      },
      { $unwind: '$ngo' },
      { $project: { name: '$ngo.name', email: '$ngo.email', fulfilled: 1 } },
    ]),

    // ── Estimated food waste reduced (kg delivered) ────────────────────────
    Donation.aggregate([
      { $match: { status: 'delivered', 'quantity.unit': 'kg' } },
      { $group: { _id: null, totalKg: { $sum: '$quantity.value' } } },
    ]),
  ]);

  // Format user stats into a map
  const users = userStats.reduce(
    (acc, r) => ({ ...acc, [r._id]: { total: r.count, active: r.active } }),
    {}
  );

  const donations = donationStats[0] || { total: 0, thisMonth: 0, totalQuantityKg: 0 };

  const statusMap = donationByStatus.reduce((acc, r) => ({ ...acc, [r._id]: r.count }), {});

  return {
    period: `${days} days`,
    generatedAt: new Date().toISOString(),
    users,
    donations: {
      ...donations,
      byStatus: statusMap,
      byFoodType: donationByFoodType,
    },
    requests: requestStats.reduce((acc, r) => ({ ...acc, [r._id]: r.count }), {}),
    pickups: pickupStats.reduce((acc, r) => ({ ...acc, [r._id]: r.count }), {}),
    ratings: ratingStats,
    areaWiseDistribution,
    donationsOverTime,
    topDonors,
    topNGOs,
    impact: {
      wasteReducedKg: wasteReduced[0]?.totalKg || 0,
      estimatedPeopleFed: Math.round((wasteReduced[0]?.totalKg || 0) * 4),
    },
  };
};

module.exports = { getPlatformAnalytics };

